import { MODULE_ID } from "./constants";
import {
  DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING,
  DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING,
  type DamageCategoryMapping,
  sanitizeDamageCategoryMapping,
} from "../functions/critical-hits/damage-inference";

export const ENABLE_CRITICAL_REPLACEMENT_SETTING = "enableCriticalReplacement";
export const ENABLE_NATURAL_ONE_CRITICALS_SETTING = "enableNaturalOneCriticals";
export const INFER_DAMAGE_FROM_WEAPON_PROPERTIES_SETTING = "inferDamageFromWeaponProperties";
export const INFER_DAMAGE_FROM_WEAPON_TYPES_SETTING = "inferDamageFromWeaponTypes";
export const WEAPON_PROPERTY_DAMAGE_MAPPING_SETTING = "weaponPropertyDamageMapping";
export const WEAPON_TYPE_DAMAGE_MAPPING_SETTING = "weaponTypeDamageMapping";

const DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING_JSON = JSON.stringify(
  DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING,
);
const DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING_JSON = JSON.stringify(
  DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING,
);

export function registerModuleSettings(): void {
  game.settings.register(MODULE_ID, ENABLE_CRITICAL_REPLACEMENT_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.enableCriticalReplacement.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.enableCriticalReplacement.hint",
    scope: "world",
    config: true,
    default: false,
    type: Boolean,
  });

  game.settings.register(MODULE_ID, ENABLE_NATURAL_ONE_CRITICALS_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.enableNaturalOneCriticals.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.enableNaturalOneCriticals.hint",
    scope: "world",
    config: true,
    default: false,
    type: Boolean,
  });

  game.settings.register(MODULE_ID, INFER_DAMAGE_FROM_WEAPON_PROPERTIES_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.inferDamageFromWeaponProperties.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.inferDamageFromWeaponProperties.hint",
    scope: "world",
    config: true,
    default: true,
    type: Boolean,
  });

  game.settings.register(MODULE_ID, WEAPON_PROPERTY_DAMAGE_MAPPING_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.weaponPropertyDamageMapping.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.weaponPropertyDamageMapping.hint",
    scope: "world",
    config: true,
    default: DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING_JSON,
    type: String,
  });

  game.settings.register(MODULE_ID, INFER_DAMAGE_FROM_WEAPON_TYPES_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.inferDamageFromWeaponTypes.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.inferDamageFromWeaponTypes.hint",
    scope: "world",
    config: true,
    default: false,
    type: Boolean,
  });

  game.settings.register(MODULE_ID, WEAPON_TYPE_DAMAGE_MAPPING_SETTING, {
    name: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.weaponTypeDamageMapping.name",
    hint: "WFRP4E_EXPANDED_CRITICAL_HITS.settings.weaponTypeDamageMapping.hint",
    scope: "world",
    config: true,
    default: DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING_JSON,
    type: String,
  });
}

export function isCriticalReplacementEnabled(): boolean {
  return Boolean(game.settings.get(MODULE_ID, ENABLE_CRITICAL_REPLACEMENT_SETTING));
}

export function isNaturalOneCriticalsEnabled(): boolean {
  return Boolean(game.settings.get(MODULE_ID, ENABLE_NATURAL_ONE_CRITICALS_SETTING));
}

export async function normalizeStoredMappingSettings(): Promise<void> {
  if (!game.user.isGM) {
    return;
  }

  await normalizeStoredMappingSetting(
    WEAPON_PROPERTY_DAMAGE_MAPPING_SETTING,
    DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING_JSON,
  );
  await normalizeStoredMappingSetting(
    WEAPON_TYPE_DAMAGE_MAPPING_SETTING,
    DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING_JSON,
  );
}

export function isWeaponPropertyDamageInferenceEnabled(): boolean {
  return Boolean(game.settings.get(MODULE_ID, INFER_DAMAGE_FROM_WEAPON_PROPERTIES_SETTING));
}

export function isWeaponTypeDamageInferenceEnabled(): boolean {
  return Boolean(game.settings.get(MODULE_ID, INFER_DAMAGE_FROM_WEAPON_TYPES_SETTING));
}

export function getWeaponPropertyDamageMapping(): DamageCategoryMapping {
  return sanitizeDamageCategoryMapping(
    game.settings.get(MODULE_ID, WEAPON_PROPERTY_DAMAGE_MAPPING_SETTING),
  );
}

export function getWeaponTypeDamageMapping(): DamageCategoryMapping {
  return sanitizeDamageCategoryMapping(
    game.settings.get(MODULE_ID, WEAPON_TYPE_DAMAGE_MAPPING_SETTING),
  );
}

async function normalizeStoredMappingSetting(key: string, defaultJson: string): Promise<void> {
  const value = game.settings.get(MODULE_ID, key);

  if (typeof value === "object" && value !== null) {
    await game.settings.set(MODULE_ID, key, JSON.stringify(value));

    return;
  }

  if (value === "[object Object]") {
    await game.settings.set(MODULE_ID, key, defaultJson);
  }
}
