import type { DamageCategory } from "../../types/critical-hits";

import { detectDamageCategories } from "../../functions/critical-hits/damage-categories";
import { asArray, asRecord } from "./runtime-values";

export interface DamageCategoryClues {
  explicitCategories: DamageCategory[];
  weaponPropertyKeys: string[];
  weaponTypeKeys: string[];
}

export function getDamageCategoriesFromItem(item: unknown): DamageCategory[] {
  return detectDamageCategories(getQualityKeysFromItem(item));
}

export function getDamageCategoryCluesFromItem(item: unknown): DamageCategoryClues {
  const qualityKeys = getQualityKeysFromItem(item);

  return {
    explicitCategories: detectDamageCategories(qualityKeys),
    weaponPropertyKeys: qualityKeys,
    weaponTypeKeys: getWeaponTypeKeysFromItem(item),
  };
}

function getQualityKeysFromItem(item: unknown): string[] {
  const itemRecord = asRecord(item);
  const system = asRecord(itemRecord?.["system"]);
  const directProperties = asRecord(itemRecord?.["properties"]);
  const systemProperties = asRecord(system?.["properties"]);
  const qualityObjects = [
    asRecord(directProperties?.["qualities"]),
    asRecord(systemProperties?.["qualities"]),
  ];
  const qualityKeys = new Set<string>();

  for (const qualities of qualityObjects) {
    for (const key of Object.keys(qualities ?? {})) {
      qualityKeys.add(key);
    }
  }

  const qualityValues = asArray(asRecord(system?.["qualities"])?.["value"]);

  for (const qualityValue of qualityValues) {
    const qualityName = asRecord(qualityValue)?.["name"];

    if (typeof qualityName === "string") {
      qualityKeys.add(qualityName);
    }
  }

  return [...qualityKeys];
}

function getWeaponTypeKeysFromItem(item: unknown): string[] {
  const itemRecord = asRecord(item);
  const system = asRecord(itemRecord?.["system"]);
  const keys = new Set<string>();

  for (const value of [
    system?.["weaponGroup"],
    system?.["group"],
    system?.["weaponType"],
    system?.["weaponClass"],
    system?.["ammunitionGroup"],
    system?.["ammoGroup"],
    system?.["category"],
  ]) {
    collectStringKeys(value, keys);
  }

  return [...keys];
}

function collectStringKeys(value: unknown, keys: Set<string>): void {
  if (typeof value === "string") {
    keys.add(value);

    return;
  }

  if (Array.isArray(value)) {
    for (const entry of value) {
      collectStringKeys(entry, keys);
    }

    return;
  }

  const record = asRecord(value);

  if (!record) {
    return;
  }

  for (const key of ["key", "id", "name", "label", "value", "type"]) {
    collectStringKeys(record[key], keys);
  }
}
