import { DAMAGE_CATEGORIES, type DamageCategory } from "../../../types/critical-hits";

export type DamageCategoryMapping = Record<string, DamageCategory>;

export interface DamageCategoryResolutionInput {
  explicitCategories: readonly DamageCategory[];
  inferFromWeaponProperties: boolean;
  inferFromWeaponTypes: boolean;
  weaponPropertyKeys: readonly string[];
  weaponPropertyMapping: DamageCategoryMapping;
  weaponTypeKeys: readonly string[];
  weaponTypeMapping: DamageCategoryMapping;
}

export interface DamageCategoryResolution {
  categories: DamageCategory[];
  source: "explicit" | "weaponProperty" | "weaponType" | "none";
}

export const DEFAULT_WEAPON_PROPERTY_DAMAGE_CATEGORY_MAPPING: DamageCategoryMapping = {
  hack: "cutting",
  impale: "piercing",
  pummel: "crushing",
  slash: "cutting",
};

export const DEFAULT_WEAPON_TYPE_DAMAGE_CATEGORY_MAPPING: DamageCategoryMapping = {
  basic: "cutting",
  blackpowder: "bullets",
  bow: "arrowsBolts",
  brawling: "unarmed",
  cavalry: "cutting",
  crossbow: "arrowsBolts",
  engineering: "shrapnelShot",
  explosives: "shrapnelShot",
  fencing: "piercing",
  flail: "crushing",
  parry: "cutting",
  polearm: "piercing",
  sling: "sling",
  throwing: "piercing",
  twohanded: "cutting",
};

export function resolveDamageCategories(
  input: DamageCategoryResolutionInput,
): DamageCategoryResolution {
  if (input.explicitCategories.length > 0) {
    return { categories: orderCategories(input.explicitCategories), source: "explicit" };
  }

  if (input.inferFromWeaponProperties) {
    const categories = mapKeysToDamageCategories(
      input.weaponPropertyKeys,
      input.weaponPropertyMapping,
    );

    if (categories.length > 0) {
      return { categories, source: "weaponProperty" };
    }
  }

  if (input.inferFromWeaponTypes) {
    const categories = mapKeysToDamageCategories(input.weaponTypeKeys, input.weaponTypeMapping);

    if (categories.length > 0) {
      return { categories, source: "weaponType" };
    }
  }

  return { categories: [], source: "none" };
}

export function normalizeInferenceKey(value: string): string {
  return value
    .trim()
    .toLowerCase()
    .replaceAll(/[^a-z0-9]/g, "");
}

export function sanitizeDamageCategoryMapping(value: unknown): DamageCategoryMapping {
  const source = parseMappingSource(value);
  const mapping: DamageCategoryMapping = {};

  for (const [key, category] of Object.entries(source ?? {})) {
    if (isDamageCategory(category)) {
      mapping[normalizeInferenceKey(key)] = category;
    }
  }

  return mapping;
}

function parseMappingSource(value: unknown): Record<string, unknown> | undefined {
  if (typeof value === "string") {
    try {
      return parseMappingSource(JSON.parse(value));
    } catch {
      return undefined;
    }
  }

  if (typeof value === "object" && value !== null && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }

  return undefined;
}

function mapKeysToDamageCategories(
  keys: readonly string[],
  mapping: DamageCategoryMapping,
): DamageCategory[] {
  const normalizedMapping = sanitizeDamageCategoryMapping(mapping);
  const mappedCategories = keys.flatMap((key) => {
    const category = normalizedMapping[normalizeInferenceKey(key)];

    return category ? [category] : [];
  });

  return orderCategories(mappedCategories);
}

function orderCategories(categories: readonly DamageCategory[]): DamageCategory[] {
  const uniqueCategories = new Set(categories);

  return DAMAGE_CATEGORIES.filter((category) => uniqueCategories.has(category));
}

function isDamageCategory(value: unknown): value is DamageCategory {
  return typeof value === "string" && DAMAGE_CATEGORIES.includes(value as DamageCategory);
}
