import type { ItemPropertiesApplication } from "./types";

import { WOUNDING_TYPE_LABELS } from "../../../functions/critical-hits/damage-categories";
import {
  getItemDocumentUuid,
  openItemPropertiesDialog,
  registerItemPropertiesOpener,
} from "./actions";
import {
  asItemPropertiesApplication,
  getDamageTypeLabelsFromDocument,
  supportsDamageTypeProperties,
  supportsStandaloneDamageTypeRow,
  WOUNDING_QUALITY_KEYS,
  WOUNDING_SECTION_CLASS,
} from "./support";

export function groupRenderedWoundingProperties(element: unknown): void {
  if (!(element instanceof HTMLElement)) {
    return;
  }

  const qualityColumn = element.querySelector(".property-column");

  if (!qualityColumn) {
    return;
  }

  const woundingRows = getRenderedWoundingRows(qualityColumn);

  if (woundingRows.length === 0) {
    return;
  }

  const existingSection = qualityColumn.querySelector(`.${WOUNDING_SECTION_CLASS}`);
  const woundingSection = existingSection ?? document.createElement("div");

  if (!existingSection) {
    woundingSection.classList.add(WOUNDING_SECTION_CLASS);
    woundingSection.append(createWoundingHeader());
  }

  for (const row of woundingRows) {
    woundingSection.append(row);
  }

  const customQualityRow = qualityColumn.querySelector<HTMLInputElement>(
    'input[name="custom-quality"]',
  )?.parentElement;

  if (customQualityRow) {
    customQualityRow.before(woundingSection);
    return;
  }

  qualityColumn.append(woundingSection);
}

export function splitRenderedItemSheetWoundingProperties(
  application: unknown,
  element: unknown,
): void {
  if (!(element instanceof HTMLElement)) {
    return;
  }

  const sheetApplication = asItemPropertiesApplication(application);
  const document = sheetApplication?.document ?? sheetApplication?.item;

  if (!supportsDamageTypeProperties(document)) {
    return;
  }

  const qualitiesBox = findItemSheetQualitiesBox(element);

  if (!qualitiesBox) {
    maybeAppendStandaloneDamageTypeBox(application, element, document);
    return;
  }

  const qualitiesInput = qualitiesBox.querySelector<HTMLInputElement>(".field input");

  if (!qualitiesInput) {
    return;
  }

  const splitQualities = splitWoundingQualityDisplay(qualitiesInput.value);

  if (splitQualities.wounding.length === 0) {
    return;
  }

  qualitiesInput.value = splitQualities.normal.join(",");

  qualitiesBox.parentElement?.querySelector(`.${WOUNDING_SECTION_CLASS}__sheet-row`)?.remove();
  qualitiesBox.after(createItemSheetWoundingBox(application, splitQualities.wounding, document));
}

function getRenderedWoundingRows(qualityColumn: Element): HTMLElement[] {
  const checkboxes = qualityColumn.querySelectorAll<HTMLInputElement>('input[type="checkbox"]');
  const rows: HTMLElement[] = [];

  for (const checkbox of checkboxes) {
    if (!WOUNDING_QUALITY_KEYS.has(checkbox.name)) {
      continue;
    }

    const row = checkbox.closest<HTMLElement>(".form-group");

    if (row) {
      rows.push(row);
    }
  }

  return rows;
}

function createWoundingHeader(): HTMLHeadingElement {
  const header = document.createElement("h2");
  header.classList.add("property-header", `${WOUNDING_SECTION_CLASS}__header`);
  header.textContent = "Damage Type";

  return header;
}

function maybeAppendStandaloneDamageTypeBox(
  application: unknown,
  element: HTMLElement,
  document: ItemPropertiesApplication["document"],
): void {
  if (!supportsStandaloneDamageTypeRow(document)) {
    return;
  }

  const existingRow = element.querySelector(`.${WOUNDING_SECTION_CLASS}__sheet-row`);

  if (existingRow) {
    return;
  }

  const damageSection = findDamageFieldset(element);

  if (!damageSection) {
    return;
  }

  const labels = getDamageTypeLabelsFromDocument(document);
  damageSection.after(createItemSheetWoundingBox(application, labels, document));
}

function findItemSheetQualitiesBox(element: HTMLElement): HTMLElement | undefined {
  const propertyActions = element.querySelectorAll<HTMLAnchorElement>(
    'a[data-action="configureProperties"]',
  );

  for (const action of propertyActions) {
    if (action.textContent.trim().startsWith("Qualities")) {
      return action.closest<HTMLElement>(".attribute-box") ?? undefined;
    }
  }

  return undefined;
}

function splitWoundingQualityDisplay(value: string): { normal: string[]; wounding: string[] } {
  const normal: string[] = [];
  const wounding: string[] = [];
  const woundingLabels = new Set(Object.values(WOUNDING_TYPE_LABELS));

  for (const quality of value.split(",")) {
    const label = quality.trim();

    if (!label) {
      continue;
    }

    if (woundingLabels.has(label)) {
      wounding.push(label);
      continue;
    }

    normal.push(label);
  }

  return { normal, wounding };
}

function createItemSheetWoundingBox(
  application: unknown,
  woundingLabels: string[],
  itemDocument: ItemPropertiesApplication["document"],
): HTMLDivElement {
  const box = document.createElement("div");
  box.classList.add("attribute-box", "top-label", `${WOUNDING_SECTION_CLASS}__sheet-row`);

  const itemUuid = getItemDocumentUuid(itemDocument);

  if (itemUuid) {
    box.dataset["echItemUuid"] = itemUuid;
    registerItemPropertiesOpener(
      itemUuid,
      createConfigurePropertiesOpener(application, itemDocument),
    );
  }

  const label = document.createElement("div");
  label.classList.add("label");
  label.style.gridColumn = "1 / span 12";
  label.innerHTML =
    '<label><a data-ech-action="configureProperties">Damage Type <i class="fas fa-cog"></i></a></label>';

  const field = document.createElement("div");
  field.classList.add("field");
  field.style.gridColumn = "1 / span 12";

  const input = document.createElement("input");
  input.type = "text";
  input.value = woundingLabels.join(",");
  input.readOnly = true;

  field.append(input);
  box.append(label, field);
  bindConfigurePropertiesAction(box, itemDocument);

  return box;
}

interface WfrpItemSheetConstructor {
  DEFAULT_OPTIONS?: {
    actions?: {
      configureProperties?: unknown;
    };
  };
}

function bindConfigurePropertiesAction(
  box: HTMLDivElement,
  itemDocument: ItemPropertiesApplication["document"],
): void {
  const action = box.querySelector<HTMLAnchorElement>('a[data-ech-action="configureProperties"]');

  action?.addEventListener("click", (event) => {
    event.preventDefault();
    openItemPropertiesDialog(itemDocument);
  });
}

function createConfigurePropertiesOpener(
  application: unknown,
  itemDocument: ItemPropertiesApplication["document"],
): (itemDocument: ItemPropertiesApplication["document"]) => void {
  const configurePropertiesOpener = getConfigurePropertiesOpener(application);

  if (!configurePropertiesOpener) {
    return (resolvedItemDocument) => {
      openItemPropertiesDialog(resolvedItemDocument ?? itemDocument);
    };
  }

  return configurePropertiesOpener;
}

function getConfigurePropertiesOpener(
  application: unknown,
): ((itemDocument: ItemPropertiesApplication["document"]) => void) | undefined {
  if (typeof application !== "object" || application === null) {
    return undefined;
  }

  const constructor = (application as { constructor?: WfrpItemSheetConstructor }).constructor;
  const configurePropertiesAction = constructor?.DEFAULT_OPTIONS?.actions?.configureProperties;

  if (typeof configurePropertiesAction !== "function") {
    return undefined;
  }

  return (itemDocument) => {
    configurePropertiesAction.call({ document: itemDocument });
  };
}

function findDamageFieldset(element: HTMLElement): HTMLElement | undefined {
  const sections = element.querySelectorAll("fieldset");

  for (const fieldset of sections) {
    const legendText = fieldset.querySelector("legend")?.textContent.trim();

    if (legendText === "Damage") {
      return fieldset;
    }
  }

  return undefined;
}
