import { createModuleApi } from "./create-module-api";
import { MODULE_ID } from "../constants";

export function registerModuleApi(): void {
  if (!game) {
    throw new Error("Foundry game global is unavailable during module API registration.");
  }

  const moduleEntry = game.modules.get(MODULE_ID);

  if (!moduleEntry) {
    throw new Error(`Foundry module registry entry was not found for ${MODULE_ID}.`);
  }

  moduleEntry.api = createModuleApi();
}
