import { WOUNDING_TYPE_QUALITY_KEYS } from "../../functions/critical-hits/damage-categories";
import { WOUNDING_TYPES } from "../../types/critical-hits";
import {
  appendWoundingLabels,
  installWoundingPropertyDisplayHooks,
} from "./wounding-properties/display";

let qualityListPatchInstalled = false;

export function registerExpandedDamageQualities(): void {
  const config = game.wfrp4e?.config;

  if (!config) {
    return;
  }

  const propertyHasValue = config.propertyHasValue;
  const qualityDescriptions = config.qualityDescriptions;

  if (!propertyHasValue || !qualityDescriptions) {
    return;
  }

  for (const woundingType of WOUNDING_TYPES) {
    const qualityKey = WOUNDING_TYPE_QUALITY_KEYS[woundingType];

    qualityDescriptions[qualityKey] =
      `Expanded Critical Hits damage type marker. A critical hit may roll on the matching expanded critical table.`;
    propertyHasValue[qualityKey] = false;
  }

  installQualityListPatch();
  installWoundingPropertyDisplayHooks();
}

function installQualityListPatch(): void {
  const utility = game.wfrp4e?.utility;
  const originalQualityList = utility?.qualityList;

  if (qualityListPatchInstalled || !utility || !originalQualityList) {
    return;
  }

  utility.qualityList = function qualityListWithWoundingTypes(type?: null | string) {
    const qualities = originalQualityList.call(this, type);

    if (type === "armor") {
      return qualities;
    }

    return appendWoundingLabels(qualities);
  };

  qualityListPatchInstalled = true;
}
